// RegisterCSS adds every generated CSS tool to the registry.
func RegisterCSS(r *tools.Registry) {
	r.MustRegister(NewCSSAddRule())
	r.MustRegister(NewCSSCollectClassNames())
	r.MustRegister(NewCSSCreateStyleSheet())
	r.MustRegister(NewCSSForcePseudoState())
	r.MustRegister(NewCSSForceStartingStyle())
	r.MustRegister(NewCSSGetAnimatedStylesForNode())
	r.MustRegister(NewCSSGetBackgroundColors())
	r.MustRegister(NewCSSGetComputedStyleForNode())
	r.MustRegister(NewCSSGetEnvironmentVariables())
	r.MustRegister(NewCSSGetInlineStylesForNode())
	r.MustRegister(NewCSSGetLayersForNode())
	r.MustRegister(NewCSSGetLocationForSelector())
	r.MustRegister(NewCSSGetLonghandProperties())
	r.MustRegister(NewCSSGetMatchedStylesForNode())
	r.MustRegister(NewCSSGetMediaQueries())
	r.MustRegister(NewCSSGetPlatformFontsForNode())
	r.MustRegister(NewCSSGetStyleSheetText())
	r.MustRegister(NewCSSResolveValues())
	r.MustRegister(NewCSSSetContainerQueryText())
	r.MustRegister(NewCSSSetEffectivePropertyValueForNode())
	r.MustRegister(NewCSSSetKeyframeKey())
	r.MustRegister(NewCSSSetLocalFontsEnabled())
	r.MustRegister(NewCSSSetMediaText())
	r.MustRegister(NewCSSSetNavigationText())
	r.MustRegister(NewCSSSetPropertyRulePropertyName())
	r.MustRegister(NewCSSSetRuleSelector())
	r.MustRegister(NewCSSSetScopeText())
	r.MustRegister(NewCSSSetStyleSheetText())
	r.MustRegister(NewCSSSetStyleTexts())
	r.MustRegister(NewCSSSetSupportsText())
	r.MustRegister(NewCSSStartRuleUsageTracking())
	r.MustRegister(NewCSSStopRuleUsageTracking())
	r.MustRegister(NewCSSTakeComputedStyleUpdates())
	r.MustRegister(NewCSSTakeCoverageDelta())
	r.MustRegister(NewCSSTrackComputedStyleUpdates())
	r.MustRegister(NewCSSTrackComputedStyleUpdatesForNode())
}
